(() => {
    'use strict';
    const container = {{DOM_CONTEXT}};
    if (!container) return;

    let animationId;
    const canvas = container.querySelector('.lower-third-canvas');
    const ctx = canvas ? canvas.getContext('2d') : null;

    if (canvas) {
        canvas.width = 1920;
        canvas.height = 1080;
    }

    const config = { font: "Bahnschrift", black: "#000000", white: "#FFFFFF" };
    const BAR_W = 1575, BAR_H = 110, SUB_W = 1575, SUB_H = 60, OUTER_MARGIN = 30;
    const x = OUTER_MARGIN; 
    const y = 1080 - BAR_H - SUB_H - 115; 

    let progress = 0, state = 'IN';
    const ease = t => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;

    function animate() {
        if (!ctx || state === 'HIDDEN') return;
        ctx.clearRect(0, 0, 1920, 1080);

        if (state === 'IN') {
            progress += 0.025;
            if (progress >= 1) { progress = 1; state = 'STAY'; }
        } else if (state === 'OUT') {
            progress -= 0.035;
            if (progress <= 0) { progress = 0; state = 'HIDDEN'; return; }
        }

        const p = ease(progress);

        // 1. BELKA PODTYTUŁU
        if (p > 0.2) {
            const sp = Math.min((progress - 0.2) * 1.5, 1);
            ctx.save();
            ctx.globalAlpha = 0.9;
            const subGrad = ctx.createLinearGradient(x, y + BAR_H, x + SUB_W, y + BAR_H);
            subGrad.addColorStop(0, "#d1d1d1"); subGrad.addColorStop(1, "#f0f0f0");

            ctx.fillStyle = subGrad;
            ctx.fillRect(x, y + BAR_H, SUB_W * ease(sp), SUB_H);

            if (sp > 0.5) {
                ctx.globalAlpha = sp;
                ctx.fillStyle = config.black;
                ctx.font = `400 32px "${config.font}"`;
                ctx.textBaseline = "middle";
                const subEl = container.querySelector('#f-subtitle-val');
                const subText = subEl ? subEl.innerText : '';
                ctx.fillText(subText, x + 30, y + BAR_H + (SUB_H / 2));
            }
            ctx.restore();
        }

        // 2. BELKA GŁÓWNA
        const curW = BAR_W * p;
        if (curW > 0) {
            ctx.save();
            const mainGrad = ctx.createLinearGradient(x, y, x + BAR_W, y);
            mainGrad.addColorStop(0, "#ffffff"); mainGrad.addColorStop(0.5, "#e0e0e0"); mainGrad.addColorStop(1, "#ffffff");

            ctx.fillStyle = mainGrad;
            ctx.fillRect(x, y, curW, BAR_H);
            ctx.fillStyle = config.black;
            ctx.globalAlpha = 0.1;
            ctx.fillRect(x, y + BAR_H - 4, curW, 4);
            ctx.restore();
        }

        // 3. TYTUŁ
        if (p > 0.4) {
            const tp = Math.min((progress - 0.4) * 2, 1);
            ctx.save();
            ctx.globalAlpha = tp;
            ctx.fillStyle = config.black;
            ctx.font = `bold 80px "${config.font}"`; 
            ctx.textBaseline = "middle";
            const titleEl = container.querySelector('#f-title-val');
            const titleText = titleEl ? titleEl.innerText : '';
            ctx.fillText(titleText, x + 30, y + (BAR_H / 2));
            ctx.restore();
        }

        animationId = requestAnimationFrame(animate);
    }

    animate();

    // Wykrywanie kliknięcia "Zdejmij z Wizji" (usunięcie klasy .active)
    const observer = new MutationObserver((mutations) => {
        mutations.forEach((mutation) => {
            if (mutation.attributeName === 'class' && !container.classList.contains('active')) {
                state = 'OUT';
            }
        });
    });
    observer.observe(container, { attributes: true });
})();

(() => {
    const container = {{DOM_CONTEXT}};
    const canvas = container.querySelector('.lower-third-canvas');
    const ctx = canvas.getContext('2d');
    canvas.width = 1920; canvas.height = 1080;

    const BAR_W = 1575, BAR_H = 170, TAG_W = 380, TAG_H = 40, OUTER_MARGIN = 30;
    const x = OUTER_MARGIN, y = 1080 - BAR_H - 115;
    let progress = 0, state = 'IN', animationId;
    const ease = t => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;

    function animate() {
        if (!ctx || state === 'HIDDEN') return;
        ctx.clearRect(0, 0, 1920, 1080);
        if (state === 'IN') { progress += 0.025; if (progress >= 1) state = 'STAY'; }
        else if (state === 'OUT') { progress -= 0.04; if (progress <= 0) { state = 'HIDDEN'; return; } }

        const p = ease(progress);
        if (p > 0.4) {
            ctx.save();
            const tagGrad = ctx.createLinearGradient(x, y - TAG_H, x + TAG_W, y - TAG_H);
            tagGrad.addColorStop(0, "#e91e63"); tagGrad.addColorStop(1, "#f44336");
            ctx.fillStyle = tagGrad; ctx.globalAlpha = Math.min((p - 0.4) * 2, 1);
            ctx.fillRect(x, y - TAG_H, TAG_W, TAG_H);
            ctx.fillStyle = "#fff"; ctx.font = "bold 24px Bahnschrift"; ctx.textAlign = "center";
            ctx.fillText("WYDANIE SPECJALNE", x + (TAG_W / 2), y - (TAG_H / 2) + 8);
            ctx.restore();
        }
        ctx.save();
        const mainGrad = ctx.createLinearGradient(x, y, x + BAR_W, y);
        mainGrad.addColorStop(0, "#4a0404"); mainGrad.addColorStop(0.5, "#8b0000"); mainGrad.addColorStop(1, "#ff0000");
        ctx.fillStyle = mainGrad; ctx.fillRect(x, y, BAR_W * p, BAR_H);
        ctx.restore();

        if (p > 0.8) {
            ctx.save(); ctx.globalAlpha = Math.min((progress - 0.8) * 5, 1);
            ctx.fillStyle = "#fff"; ctx.font = "bold 80px Bahnschrift"; ctx.textBaseline = "middle";
            ctx.fillText(container.querySelector('#f-special-title').innerText, x + 20, y + (BAR_H / 2) + 5);
            ctx.restore();
        }
        animationId = requestAnimationFrame(animate);
    }
    animate();
    new MutationObserver(() => { if(!container.classList.contains('active')) state = 'OUT'; }).observe(container, {attributes:true});
})();
